// 1. Get the raw string that the Gemini LLM generated
const rawString = $input.first().json.text;

// 2. Parse that string into a real JavaScript object
const data = JSON.parse(rawString);

// 3. Create the HTML template and inject the variables
const htmlTemplate = `
  <html>
    <body style="font-family: Arial, sans-serif; padding: 40px; color: #333;">
      <h1 style="color: #2c3e50;">Invoice</h1>
      <p><strong>Billed To:</strong> ${data.customerName}</p>
      <hr style="border: 1px solid #eee; margin: 20px 0;">

      <table style="width: 100%; border-collapse: collapse;">
        <tr style="background-color: #f8f9fa; text-align: left;">
          <th style="padding: 10px; border-bottom: 2px solid #ddd;">Item</th>
          <th style="padding: 10px; border-bottom: 2px solid #ddd;">Qty</th>
          <th style="padding: 10px; border-bottom: 2px solid #ddd;">Unit Price</th>
        </tr>
        ${data.items.map(item => `
          <tr>
            <td style="padding: 10px; border-bottom: 1px solid #eee;">${item.itemName}</td>
            <td style="padding: 10px; border-bottom: 1px solid #eee;">${item.quantity}</td>
            <td style="padding: 10px; border-bottom: 1px solid #eee;">₹${item.unitPrice}</td>
          </tr>
        `).join('')}
      </table>

      <h2 style="text-align: right; margin-top: 30px; color: #2c3e50;">
        Total: ₹${data.totalAmount}
      </h2>
    </body>
  </html>
`;

// 4. Return the HTML string so the PDF converter node can use it
return [{ 
    json: { 
        htmlString: htmlTemplate 
    } 
}];
